  const [custom, setCustom] = useState(loadCustom)

  // Profile state
  const [profilePhoto, setProfilePhoto] = useState(null)
  const [editingName, setEditingName] = useState(false)
  const [nameInput, setNameInput] = useState('')
  const [nameError, setNameError] = useState('')
  const nameInputRef = useRef(null)

  // Sync XP/achievements to cloud on mount (when authenticated)
  React.useEffect(() => {
    if (isAuthenticated && user?.uid) {
      loadXPData(user.uid).catch(err => console.error('XP cloud load failed:', err))
    }
    return () => {
      if (isAuthenticated && user?.uid) {
        syncXPData(user.uid).catch(() => { })
      }
    }
  }, [isAuthenticated, user?.uid])

  const profileName = isAuthenticated ? (user?.displayName || 'Player') : 'Guest Player'

  useEffect(() => {
    const savedPhoto = localStorage.getItem('profilePhoto')
    if (savedPhoto) {
      setProfilePhoto(savedPhoto)
    } else if (user?.photoURL) {
      setProfilePhoto(user.photoURL)
    }
  }, [user?.photoURL])

  // Update a customization value
  const updateCustom = (key, value) => {
    setCustom(prev => {
      const next = { ...prev, [key]: value }
      saveCustom(next)
      return next
    })
  }

  // Stats from XP Engine
  const stats = xpData ? getStats(xpData) : {
    level: 1, title: 'Newcomer', emoji: '­ƒò╣´©Å',
    xpInLevel: 0, xpNeeded: 100, progress: 0,
    gamesPlayed: 0, totalFavorites: 0, totalPlaytimeMin: 0,
    currentStreak: 0, bestStreak: 0, unlockedCount: 0,
    totalAchievements: 12, xpLog: []
  }

  const animGames = useCountUp(stats.gamesPlayed)
  const animPlaytime = useCountUp(stats.totalPlaytimeMin)
  const animStreak = useCountUp(stats.currentStreak)

  const favoriteGames = games.filter(g => favorites.includes(g.id))

  // Handlers
  const handlePhotoUpload = (e) => {
    const file = e.target.files?.[0]
    if (!file) return
    const reader = new FileReader()
    reader.onload = (ev) => {
      setProfilePhoto(ev.target?.result)
      localStorage.setItem('profilePhoto', ev.target?.result)
      window.dispatchEvent(new Event('profilePhotoChanged'))
    }
    reader.readAsDataURL(file)
  }

  const removePhoto = () => {
    setProfilePhoto(null)
    localStorage.removeItem('profilePhoto')
    window.dispatchEvent(new Event('profilePhotoChanged'))
  }

  const saveUsername = async () => {
    const check = checkUsername(nameInput)
    if (!check.isClean) { setNameError(check.reason); return }
    try {
      if (isAuthenticated && user?.uid) {
        await updateUserProfile(user.uid, { displayName: nameInput.trim() })
        setUsername(nameInput.trim())
      }
      setEditingName(false); setNameError('')
    } catch { setNameError('Failed to update') }
  }

  const accent = custom.avatarColor


  // Next Closest Achievement Logic
  const nextAch = ACHIEVEMENTS.filter(a => !stats.unlockedAchievements?.[a.id])
    .map(a => ({ ...a, currProg: a.progress(xpData) }))
    .sort((a, b) => b.currProg - a.currProg)[0]

  // ÔöÇÔöÇÔöÇ Render ÔöÇÔöÇÔöÇ //

  return (
    <>
      <div className={`profile cursor-${custom.cursorStyle}`}
        data-level-bar={custom.levelBarStyle}
        data-font={custom.nameFontFamily}
        data-bento={custom.bentoMaterial}
        style={{ '--accent': accent, '--bg-opacity': custom.bgOpacity / 100 }} data-bg-theme={custom.bgTheme}>
        <RetroGridBackground theme={custom.bgTheme} particles={custom.ambientParticles} />

        <div className="profile__container">

          {/* ÔòÉÔòÉÔòÉ HERO ÔòÉÔòÉÔòÉ */}
          <header className={`profile__hero profile__hero--glow-${custom.profileGlow}`}>
            <div className={`profile__hero-bg profile__hero-banner--${custom.heroBanner}`}
              style={{ opacity: custom.heroOpacity / 100, filter: `drop-shadow(0 0 ${custom.heroGlowIntensity}px var(--accent))` }} />

            <div className="profile__hero-inner">
              <div className="profile__user-row">

                {/* Avatar */}
                <div className="profile__avatar-wrap">
                  <div className={`profile__avatar-frame profile__avatar-frame--${custom.profileFrame} frame-ring-${custom.avatarRingStyle}`} style={{ borderColor: accent, "--pglow": custom.profileGlowColor }}>
                    <div className={`profile__avatar profile__avatar-vfx--${custom.avatarVfx} avatar-shape-${custom.avatarShape}`}>
